423	            justificationMetadata: ReconciliationMetadata | null;
424	          }[]
425	        >;
426	      };
427	    };
428	    const rows = await client.opinionCitation.findMany({
429	      where: { opinionId: { in: opinions.map((opinion) => opinion.id) } },
430	      select: {
431	        opinionId: true,
432	        sourceKind: true,
433	        conclusionId: true,
434	        claimId: true,
435	        quotedSpan: true,
436	        justificationMetadata: true,
437	      },
438	    });
439	
440	    const counterConclusionIds = new Set<string>();
441	    for (const row of rows) {
442	      const metadata = row.justificationMetadata ?? {};
443	      if (metadata.role !== RECONCILIATION_ROLE) continue;
444	      if (row.sourceKind?.toLowerCase() === "conclusion" && row.conclusionId) {
445	        counterConclusionIds.add(row.conclusionId);
446	      }
447	    }
448	
449	    const conclusionMetadata = await counterConclusionMetadata(
450	      Array.from(counterConclusionIds),
451	    );
452	
453	    for (const row of rows) {
454	      const metadata = row.justificationMetadata ?? {};
455	      if (metadata.role !== RECONCILIATION_ROLE) continue;
456	      const sourceId =
457	        row.conclusionId ?? row.claimId ?? asString(metadata.counter_claim_id);
458	      if (!sourceId) continue;
459	      const counterMeta = conclusionMetadata.get(sourceId);
460	      result.set(
461	        row.opinionId,
462	        reconciliationFromMetadata(metadata, counterMeta, row.quotedSpan ?? ""),
463	      );
464	    }
465	  } catch {
466	    // Without DB access we fall back to whatever the no-counter tag implies.
467	  }
468	
469	  return result;
470	}
