472	function titleFromText(text: string | null | undefined): string | null {
473	  const normalized = text?.replace(/\s+/g, " ").trim();
474	  if (!normalized) return null;
475	  return normalized.length > 140 ? `${normalized.slice(0, 137)}...` : normalized;
476	}
477	
478	function titleFromPayload(payloadJson: unknown): string | null {
479	  if (typeof payloadJson !== "string" || !payloadJson.trim()) return null;
480	  try {
481	    const payload = JSON.parse(payloadJson) as { conclusionText?: unknown; title?: unknown };
482	    if (typeof payload.conclusionText === "string") {
483	      return titleFromText(payload.conclusionText);
484	    }
485	    if (typeof payload.title === "string") return titleFromText(payload.title);
486	  } catch {
487	    return null;
488	  }
489	  return null;
490	}
491	
492	async function citationMetadataFromSources(
493	  opinion: PublicOpinion,
494	  options?: CurrentsFetchOptions,
495	): Promise<Map<string, CitationMetadata>> {
496	  const metadataBySourceId = new Map<string, CitationMetadata>();
497	  if (!opinionHasInlineCitationMarkers(opinion)) return metadataBySourceId;
498	  if (!(opinion.citations as CitationWire[]).some(citationNeedsMetadata)) {
499	    return metadataBySourceId;
500	  }
501	
502	  try {
503	    const sources = await fetchJson<SourceWire[]>(
504	      `/v1/currents/${encodeURIComponent(opinion.id)}/sources`,
505	      undefined,
506	      options,
507	    );
508	    for (const source of sources) {
509	      metadataBySourceId.set(source.source_id, sourceMetadata(source));
510	    }
511	  } catch {
512	    // Fail closed: source text may be absent, but source URLs must not leak.
513	  }
514	  return metadataBySourceId;
515	}
