517	async function citationMetadataFromPublicDb(
518	  opinions: PublicOpinion[],
519	): Promise<Map<string, CitationMetadata>> {
520	  const opinionsWithMarkers = opinions.filter(opinionHasInlineCitationMarkers);
521	  const conclusionIds = [
522	    ...new Set(
523	      opinionsWithMarkers.flatMap((opinion) =>
524	        (opinion.citations as CitationWire[])
525	          .filter((citation) => sourceKind(citation) === "conclusion")
526	          .map((citation) => citation.source_id)
527	          .filter(Boolean),
528	      ),
529	    ),
530	  ];
531	  if (!conclusionIds.length) return new Map();
532	
533	  try {
534	    const { db } = await import("@/lib/db");
535	    const client = db as {
536	      conclusion: {
537	        findMany: (args: unknown) => Promise<
538	          {
539	            id: string;
540	            text: string | null;
541	            topicHint?: string | null;
542	            sources?: {
543	              upload?: {
544	                visibility?: string | null;
545	                deletedAt?: Date | string | null;
546	              } | null;
547	            }[];
548	          }[]
549	        >;
550	      };
551	      publishedConclusion: {
552	        findMany: (args: unknown) => Promise<
553	          {
554	            sourceConclusionId: string;
555	            slug: string;
556	            version: number;
557	            payloadJson: string;
558	          }[]
559	        >;
560	      };
561	    };
562	
563	    const [conclusions, publications] = await Promise.all([
564	      client.conclusion.findMany({
565	        where: { id: { in: conclusionIds } },
566	        select: {
567	          id: true,
568	          text: true,
569	          topicHint: true,
570	          sources: {
571	            select: {
572	              upload: {
573	                select: {
574	                  visibility: true,
575	                  deletedAt: true,
576	                },
577	              },
578	            },
579	          },
580	        },
581	      }),
582	      client.publishedConclusion.findMany({
583	        where: {
584	          kind: "CONCLUSION",
585	          sourceConclusionId: { in: conclusionIds },
586	        },
587	        orderBy: [{ publishedAt: "desc" }],
588	        select: {
589	          sourceConclusionId: true,
590	          slug: true,
591	          version: true,
592	          payloadJson: true,
593	        },
594	      }),
595	    ]);
596	
597	    const latestPublication = new Map<string, (typeof publications)[number]>();
598	    for (const publication of publications) {
599	      if (!latestPublication.has(publication.sourceConclusionId)) {
600	        latestPublication.set(publication.sourceConclusionId, publication);
601	      }
602	    }
603	
604	    const metadata = new Map<string, CitationMetadata>();
605	    for (const conclusion of conclusions) {
606	      const sourceVisibilities = (conclusion.sources ?? [])
607	        .map((source) => source.upload)
608	        .filter((upload) => upload && !upload.deletedAt)
609	        .map((upload) => normalizedVisibility(upload?.visibility));
610	      const visibility = sourceVisibilities.includes("org")
611	        ? "org"
612	        : sourceVisibilities.find(Boolean) ?? null;
613	      const publication = latestPublication.get(conclusion.id);
614	      const publicUrl =
615	        visibility === "org" && publication
616	          ? `/c/${encodeURIComponent(publication.slug)}/v/${publication.version}`
617	          : null;
618	
619	      metadata.set(conclusion.id, {
620	        conclusionText: conclusion.text ?? null,
621	        conclusionTitle:
622	          titleFromPayload(publication?.payloadJson) ||
623	          titleFromText(conclusion.topicHint) ||
624	          titleFromText(conclusion.text),
625	        publicUrl,
626	        sourceVisibility: visibility,
627	      });
628	    }
629	    return metadata;
630	  } catch {
631	    // No DB/env access in this runtime means no public URL. That is safer than leaking.
632	    return new Map();
633	  }
634	}
635	
636	async function enrichOpinions(
637	  opinions: PublicOpinion[],
638	  options?: CurrentsFetchOptions,
639	): Promise<PublicOpinion[]> {
640	  const sourceMetadataResults = await Promise.all(
641	    opinions.map((opinion) => citationMetadataFromSources(opinion, options)),
642	  );
643	  const [dbMetadata, reconciliations] = await Promise.all([
644	    citationMetadataFromPublicDb(opinions),
645	    reconciliationsForOpinions(opinions),
646	  ]);
647	
648	  return opinions.map((opinion, index) => {
649	    const merged = new Map(sourceMetadataResults[index]);
650	    for (const [sourceId, metadata] of dbMetadata) {
651	      const existing = merged.get(sourceId);
652	      merged.set(sourceId, {
653	        conclusionText: metadata.conclusionText ?? existing?.conclusionText ?? null,
654	        conclusionTitle: metadata.conclusionTitle ?? existing?.conclusionTitle ?? null,
655	        publicUrl: metadata.publicUrl ?? existing?.publicUrl ?? null,
656	        sourceVisibility: metadata.sourceVisibility ?? existing?.sourceVisibility ?? null,
657	      });
658	    }
659	    const normalized = normalizeOpinion(opinion, merged);
660	    return {
661	      ...normalized,
662	      reconciliation: reconciliations.get(opinion.id) ?? normalized.reconciliation,
663	    };
664	  });
665	}
666	
667	export async function listCurrents(
668	  params: ListCurrentsParams,
669	  options?: CurrentsFetchOptions,
670	): Promise<{ items: PublicOpinion[] }> {
671	  const result = await fetchJson<{ items: PublicOpinion[] }>(
672	    "/v1/currents",
673	    searchParamsFor(params),
674	    options,
675	  );
676	  return { items: await enrichOpinions(result.items, options) };
677	}
678	
679	export async function getCurrentsHealth(options?: CurrentsFetchOptions): Promise<CurrentsHealth> {
680	  return fetchJson<CurrentsHealth>("/v1/currents/health", undefined, options);
681	}
682	
683	export async function getCurrent(id: string): Promise<PublicOpinion> {
684	  const opinion = await fetchJson<PublicOpinion>(`/v1/currents/${encodeURIComponent(id)}`);
685	  return (await enrichOpinions([opinion]))[0];
686	}
687	
688	export async function getCurrentSources(id: string): Promise<PublicSource[]> {
689	  return fetchJson<PublicSource[]>(`/v1/currents/${encodeURIComponent(id)}/sources`);
690	}
691	
692	export async function getFollowupMessages(
693	  id: string,
694	  session: string,
695	  search?: string,
696	): Promise<{ items: PublicFollowupMessage[]; next_before: string | null }> {
697	  return fetchJson<{ items: PublicFollowupMessage[]; next_before: string | null }>(
698	    `/v1/currents/${encodeURIComponent(id)}/follow-up/${encodeURIComponent(session)}/messages`,
699	    search ? new URLSearchParams(search) : undefined,
700	  );
701	}
702	
703	export function passThroughHeaders(req: Request): Headers {
704	  const headers = new Headers();
705	  const userAgent = req.headers.get("user-agent");
706	  const contentType = req.headers.get("content-type");
707	  const ip = clientIpFor(req);
708	
709	  if (userAgent) headers.set("user-agent", userAgent);
710	  if (contentType) headers.set("content-type", contentType);
711	  if (ip !== "unknown") headers.set("x-forwarded-for", ip);
712	  headers.set("x-request-id", req.headers.get("x-request-id") || randomUUID());
713	
714	  return headers;
715	}
716	
717	function proxiedJsonHeaders(upstream: Response): Headers {
718	  const headers = new Headers();
719	  const contentType = upstream.headers.get("content-type");
720	  const cacheControl = upstream.headers.get("cache-control");
721	  const retryAfter = upstream.headers.get("retry-after");
722	
723	  if (contentType) headers.set("content-type", contentType);
724	  if (cacheControl) headers.set("cache-control", cacheControl);
725	  if (retryAfter) headers.set("retry-after", retryAfter);
726	  return headers;
727	}
728	
729	function proxiedSseHeaders(upstream: Response): Headers {
730	  const headers = new Headers();
731	  headers.set("content-type", upstream.headers.get("content-type") || "text/event-stream; charset=utf-8");
732	  headers.set("cache-control", "no-cache, no-transform");
733	  headers.set("connection", "keep-alive");
734	  headers.set("x-accel-buffering", "no");
735	  const retryAfter = upstream.headers.get("retry-after");
736	  if (retryAfter) headers.set("retry-after", retryAfter);
737	  return headers;
738	}
739	
740	function upstreamUnavailable(error: unknown): Response {
741	  const message = error instanceof Error ? error.message : "unknown upstream failure";
742	  return new Response(JSON.stringify({ error: "currents_upstream_unavailable", detail: message }), {
743	    status: 502,
744	    headers: { "content-type": "application/json" },
745	  });
746	}
747	
748	export function proxyResponse(upstream: Response): Response {
749	  return new Response(upstream.body, {
750	    status: upstream.status,
751	    statusText: upstream.statusText,
752	    headers: proxiedJsonHeaders(upstream),
753	  });
754	}
755	
756	export function proxySseResponse(upstream: Response): Response {
757	  if (!upstream.ok) return proxyResponse(upstream);
758	  return new Response(upstream.body, {
759	    status: upstream.status,
760	    statusText: upstream.statusText,
761	    headers: proxiedSseHeaders(upstream),
762	  });
763	}
764	
765	export async function proxyToCurrents(
766	  req: Request,
767	  path: string,
768	  options: {
769	    method?: "GET" | "POST";
770	    body?: BodyInit | null;
771	    headers?: Headers;
772	    sse?: boolean;
773	  } = {},
774	): Promise<Response> {
775	  const sourceUrl = new URL(req.url);
776	  const init: StreamingRequestInit = {
777	    method: options.method ?? req.method,
778	    headers: options.headers ?? passThroughHeaders(req),
779	    cache: "no-store",
780	    redirect: "manual",
781	    signal: req.signal,
782	  };
783	
784	  if (options.body !== undefined) {
785	    init.body = options.body;
786	    if (options.body) init.duplex = "half";
787	  }
788	
789	  try {
790	    const upstream = await fetch(currentsBackendUrl(path, sourceUrl.search), init);
791	    return options.sse ? proxySseResponse(upstream) : proxyResponse(upstream);
792	  } catch (error) {
793	    return upstreamUnavailable(error);
794	  }
795	}
